pub mod config;
pub mod db;
pub mod ops;

pub use config::resolve_db_path;
pub use db::Db;
pub use ops::*;

use std::path::PathBuf;

/// Resolve the database path using priority: CLI flag > KANBAN_DB env var > XDG default.
///
/// If `cli_path` is `Some`, it takes highest priority.
/// Otherwise, the `KANBAN_DB` environment variable is checked.
/// Finally, the XDG default (`$XDG_DATA_HOME/kanban/kanban.db` or `~/.local/share/kanban/kanban.db`) is used.
pub fn resolve_db_path(cli_path: Option<&str>) -> PathBuf {
    if let Some(path) = cli_path {
        return PathBuf::from(path);
    }

    if let Ok(path) = std::env::var("KANBAN_DB") {
        return PathBuf::from(path);
    }

    xdg_default_path()
}

/// Compute the XDG default database path.
fn xdg_default_path() -> PathBuf {
    if let Some(data_home) = std::env::var_os("XDG_DATA_HOME") {
        return PathBuf::from(data_home).join("kanban").join("kanban.db");
    }

    // Fallback to ~/.local/share/kanban/kanban.db
    if let Some(base_dir) = dirs::data_local_dir() {
        return base_dir.join("kanban").join("kanban.db");
    }

    // Last resort fallback
    PathBuf::from(".kanban.db")
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::env;
    use std::sync::Mutex;

    static LOCK: Mutex<()> = Mutex::new(());

    #[test]
    fn resolve_db_path_cli_flag_wins() {
        let path = resolve_db_path(Some("/custom/path.db"));
        assert_eq!(path, PathBuf::from("/custom/path.db"));
    }

    #[test]
    fn resolve_db_path_env_var_wins_over_xdg() {
        let _lock = LOCK.lock().unwrap();
        env::set_var("KANBAN_DB", "/env/path.db");
        let path = resolve_db_path(None);
        assert_eq!(path, PathBuf::from("/env/path.db"));
        env::remove_var("KANBAN_DB");
    }

    #[test]
    fn resolve_db_path_cli_wins_over_env() {
        let _lock = LOCK.lock().unwrap();
        env::set_var("KANBAN_DB", "/env/path.db");
        let path = resolve_db_path(Some("/cli/path.db"));
        assert_eq!(path, PathBuf::from("/cli/path.db"));
        env::remove_var("KANBAN_DB");
    }

    #[test]
    fn resolve_db_path_xdg_default() {
        let _lock = LOCK.lock().unwrap();
        env::remove_var("KANBAN_DB");
        env::remove_var("XDG_DATA_HOME");
        let path = resolve_db_path(None);
        // Should resolve to a kanban.db file
        assert!(path.file_name().map(|n| n == "kanban.db").unwrap_or(false));
        env::remove_var("KANBAN_DB");
        env::remove_var("XDG_DATA_HOME");
    }

    #[test]
    fn resolve_db_path_xdg_data_home() {
        let _lock = LOCK.lock().unwrap();
        env::remove_var("KANBAN_DB");
        env::set_var("XDG_DATA_HOME", "/custom/data");
        let path = resolve_db_path(None);
        assert_eq!(path, PathBuf::from("/custom/data/kanban/kanban.db"));
        env::remove_var("XDG_DATA_HOME");
        env::remove_var("KANBAN_DB");
    }
}

use std::cell::RefCell;
use std::path::Path;

use anyhow::{Context, Result};
use rusqlite::{Connection, params};

use crate::core::{
    Board, BoardState, Column, Priority, Task,
    query_board_by_id, query_columns_by_board, query_priorities, query_tasks_by_board,
    query_all_boards,
};

/// Embedded migration SQL files. Each entry is (migration_id, name, sql).
fn embedded_migrations() -> &'static [Migration] {
    &[Migration {
        id: 1,
        name: "001_initial_schema",
        sql: include_str!("../../migrations/001_initial_schema.sql"),
    }]
}

struct Migration {
    id: i64,
    name: &'static str,
    sql: &'static str,
}

/// Database handle wrapping a rusqlite Connection with interior mutability.
pub struct Db {
    conn: RefCell<Connection>,
}

impl Db {
    /// Open a database at the given path.
    ///
    /// Creates parent directories and the DB file if missing, then runs all pending
    /// migrations in order inside a transaction.
    pub fn open(path: &Path) -> Result<Self> {
        // Create parent directories if needed
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)
                .with_context(|| format!("failed to create directory: {}", parent.display()))?;
        }

        let conn = Connection::open(path)
            .with_context(|| format!("failed to open database: {}", path.display()))?;

        // Run migrations
        run_migrations(&conn)?;

        Ok(Db {
            conn: RefCell::new(conn),
        })
    }

    /// Load the complete state of a board by its ID.
    pub fn load_board_state(&self, board_id: &str) -> Result<BoardState> {
        let conn = self.conn.borrow();
        let board = query_board(&conn, board_id)?
            .ok_or_else(|| anyhow::anyhow!("board not found: '{}'", board_id))?;
        let columns = query_columns(&conn, board_id)?;
        let tasks = query_tasks(&conn, board_id)?;
        let priorities = query_priorities_fn(&conn)?;

        Ok(BoardState {
            board,
            columns,
            tasks,
            priorities,
        })
    }

    /// List all boards.
    pub fn list_boards(&self) -> Result<Vec<Board>> {
        let conn = self.conn.borrow();
        query_all_boards_fn(&conn)
    }

    /// Get a mutable reference to the connection for transaction operations.
    pub(crate) fn conn_mut(&self) -> std::cell::RefMut<'_, Connection> {
        self.conn.borrow_mut()
    }
}

// ── Pure query functions that take &Connection ────────────────────────────

fn query_board(conn: &Connection, board_id: &str) -> Result<Option<Board>> {
    let mut stmt = conn.prepare(query_board_by_id())?;
    let board = stmt.query_map(params![board_id], |row| {
        Ok(Board {
            id: row.get(0)?,
            name: row.get(1)?,
            created_at: row.get(2)?,
            updated_at: row.get(3)?,
        })
    })?;

    let result: Vec<Board> = board.collect::<std::result::Result<Vec<_>, _>>()?;
    Ok(result.into_iter().next())
}

fn query_columns(conn: &Connection, board_id: &str) -> Result<Vec<Column>> {
    let mut stmt = conn.prepare(query_columns_by_board())?;
    let columns = stmt.query_map(params![board_id], |row| {
        Ok(Column {
            id: row.get(0)?,
            board_id: row.get(1)?,
            name: row.get(2)?,
            position: row.get(3)?,
            created_at: row.get(4)?,
            updated_at: row.get(5)?,
        })
    })?;

    columns.collect::<std::result::Result<Vec<_>, _>>().context("failed to load columns")
}

fn query_tasks(conn: &Connection, board_id: &str) -> Result<Vec<Task>> {
    let mut stmt = conn.prepare(query_tasks_by_board())?;
    let tasks = stmt.query_map(params![board_id], |row| {
        Ok(Task {
            id: row.get(0)?,
            column_id: row.get(1)?,
            title: row.get(2)?,
            description: row.get(3)?,
            priority_id: row.get(4)?,
            position: row.get(5)?,
            created_at: row.get(6)?,
            updated_at: row.get(7)?,
        })
    })?;

    tasks.collect::<std::result::Result<Vec<_>, _>>().context("failed to load tasks")
}

fn query_priorities_fn(conn: &Connection) -> Result<Vec<Priority>> {
    let mut stmt = conn.prepare(query_priorities())?;
    let priorities = stmt.query_map([], |row| {
        Ok(Priority {
            id: row.get(0)?,
            name: row.get(1)?,
        })
    })?;

    priorities
        .collect::<std::result::Result<Vec<_>, _>>()
        .context("failed to load priorities")
}

fn query_all_boards_fn(conn: &Connection) -> Result<Vec<Board>> {
    let mut stmt = conn.prepare(query_all_boards())?;
    let boards = stmt.query_map([], |row| {
        Ok(Board {
            id: row.get(0)?,
            name: row.get(1)?,
            created_at: row.get(2)?,
            updated_at: row.get(3)?,
        })
    })?;

    boards.collect::<std::result::Result<Vec<_>, _>>().context("failed to list boards")
}

/// Run all pending migrations within a transaction.
fn run_migrations(conn: &Connection) -> Result<()> {
    let migrations = embedded_migrations();
    if migrations.is_empty() {
        return Ok(());
    }

    conn.execute("BEGIN", []).context("failed to begin migration transaction")?;

    let result: Result<()> = (|| {
        let applied = get_applied_migration_ids(conn)?;

        for migration in migrations {
            if !applied.contains(&migration.id) {
                conn.execute_batch(migration.sql)
                    .with_context(|| format!("failed to apply migration {}", migration.name))?;
                // Record the migration (it was created by the migration SQL for the first one)
                let exists: bool = conn.query_row(
                    "SELECT EXISTS(SELECT 1 FROM _migrations WHERE id = ?1)",
                    params![migration.id],
                    |row| row.get(0),
                ).unwrap_or(false);
                if !exists {
                    conn.execute(
                        "INSERT INTO _migrations (id, name) VALUES (?1, ?2)",
                        params![migration.id, migration.name],
                    ).with_context(|| {
                        format!("failed to record migration {}", migration.name)
                    })?;
                }
            }
        }

        conn.execute("COMMIT", [])
            .context("failed to commit migration transaction")?;
        Ok(())
    })();

    if result.is_err() {
        let _ = conn.execute("ROLLBACK", []);
    }

    result
}

/// Get the set of already-applied migration IDs.
fn get_applied_migration_ids(conn: &Connection) -> Result<Vec<i64>> {
    let stmt = conn.prepare("SELECT id FROM _migrations ORDER BY id");
    match stmt {
        Ok(mut stmt) => {
            let ids = stmt.query_map([], |row| row.get::<_, i64>(0))
                .map(|rows| rows.collect::<std::result::Result<Vec<_>, _>>());
            match ids {
                Ok(Ok(ids)) => Ok(ids),
                _ => Ok(vec![]),
            }
        }
        Err(_) => Ok(vec![]),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::tempdir;

    #[test]
    fn open_creates_file_and_runs_migrations() {
        let dir = tempdir().unwrap();
        let path = dir.path().join("test.db");
        let db = Db::open(&path).unwrap();
        assert!(path.exists());

        // Verify tables exist by checking migrations
        let conn = db.conn.borrow();
        let migrations: Vec<i64> = conn
            .prepare("SELECT id FROM _migrations ORDER BY id")
            .unwrap()
            .query_map([], |row| row.get(0))
            .unwrap()
            .collect::<Result<Vec<_>, _>>()
            .unwrap();
        assert_eq!(migrations, vec![1]);
    }

    #[test]
    fn open_is_idempotent() {
        let dir = tempdir().unwrap();
        let path = dir.path().join("test.db");
        Db::open(&path).unwrap();
        let db = Db::open(&path).unwrap();

        let conn = db.conn.borrow();
        let migrations: Vec<i64> = conn
            .prepare("SELECT id FROM _migrations ORDER BY id")
            .unwrap()
            .query_map([], |row| row.get(0))
            .unwrap()
            .collect::<Result<Vec<_>, _>>()
            .unwrap();
        assert_eq!(migrations, vec![1]);
    }

    #[test]
    fn open_creates_parent_directories() {
        let dir = tempdir().unwrap();
        let path = dir.path().join("nested").join("deep").join("test.db");
        let db = Db::open(&path).unwrap();
        assert!(path.exists());
        // Verify it works
        let boards = db.list_boards().unwrap();
        assert!(boards.is_empty());
    }
}

use anyhow::{anyhow, Context, Result};

use crate::core::{
    Board, Column, DomainError, EntityTable, OrphanAction, Priority, SqlParam,
    Task, TaskChanges, TaskFilter,
    next_position, positions_after_move, recompute_positions, resolve_id,
    insert_board_sql, insert_column_sql, insert_task_sql, insert_priority_sql,
    update_task_sql, delete_task_sql, delete_column_sql,
    delete_tasks_by_column_sql, move_tasks_to_column_sql, update_position_sql,
    validate_title, validate_column_name, validate_priority, validate_column_exists,
};

use super::db::Db;

// ── Helper to bind SqlParam values for rusqlite ───────────────────────────

fn exec_with_params(conn: &rusqlite::Connection, sql: &str, params: &[SqlParam]) -> Result<()> {
    let rusqlite_params: Vec<&dyn rusqlite::types::ToSql> = params
        .iter()
        .map(|p| match p {
            SqlParam::Text(s) => s as &dyn rusqlite::types::ToSql,
            SqlParam::Int(i) => i as &dyn rusqlite::types::ToSql,
        })
        .collect();
    let mut stmt = conn
        .prepare(sql)
        .context("failed to prepare statement")?;
    stmt.execute(rusqlite::params_from_iter(rusqlite_params.iter().copied()))
        .context("failed to execute statement")?;
    Ok(())
}

fn exec_with_params_raw(
    conn: &rusqlite::Transaction,
    sql: &str,
    params: &[SqlParam],
) -> Result<()> {
    let rusqlite_params: Vec<&dyn rusqlite::types::ToSql> = params
        .iter()
        .map(|p| match p {
            SqlParam::Text(s) => s as &dyn rusqlite::types::ToSql,
            SqlParam::Int(i) => i as &dyn rusqlite::types::ToSql,
        })
        .collect();
    let mut stmt = conn
        .prepare(sql)
        .context("failed to prepare statement")?;
    stmt.execute(rusqlite::params_from_iter(rusqlite_params.iter().copied()))
        .context("failed to execute statement")?;
    Ok(())
}

fn now() -> String {
    chrono::Utc::now().to_rfc3339()
}

fn gen_id() -> String {
    nanoid::nanoid!(10)
}

// ── Board operations ──────────────────────────────────────────────────────

/// Initialize a new board with default columns and priorities.
pub fn init_board(db: &Db, name: &str) -> Result<Board> {
    // Check for duplicate board name
    let existing = db.list_boards().context("failed to list boards")?;
    if existing.iter().any(|b| b.name == name) {
        return Err(DomainError::DuplicateBoardName { name: name.to_string() }.into());
    }

    let board_id = gen_id();
    let timestamp = now();
    let board = Board {
        id: board_id.clone(),
        name: name.to_string(),
        created_at: timestamp.clone(),
        updated_at: timestamp.clone(),
    };

    let default_columns = [
        ("Backlog", 0),
        ("Todo", 1),
        ("Doing", 2),
        ("Done", 3),
    ];
    let default_priorities = ["low", "medium", "high"];

    let mut conn = db.conn_mut();
    let tx = conn.transaction().context("failed to begin transaction")?;

    // Insert board
    let (sql, params) = insert_board_sql(&board);
    exec_with_params_raw(&tx, &sql, &params)?;

    // Insert columns
    for (col_name, pos) in &default_columns {
        let col = Column {
            id: gen_id(),
            board_id: board_id.clone(),
            name: col_name.to_string(),
            position: *pos,
            created_at: timestamp.clone(),
            updated_at: timestamp.clone(),
        };
        let (sql, params) = insert_column_sql(&col);
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    // Insert priorities
    for prio_name in &default_priorities {
        let prio = Priority {
            id: gen_id(),
            name: prio_name.to_string(),
        };
        let (sql, params) = insert_priority_sql(&prio);
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    tx.commit().context("failed to commit transaction")?;

    Ok(board)
}

/// List all boards.
pub fn list_boards(db: &Db) -> Result<Vec<Board>> {
    db.list_boards()
}

/// Rename a board.
pub fn rename_board(db: &Db, board_id: &str, new_name: &str) -> Result<()> {
    let boards = db.list_boards()?;
    let resolved_id = resolve_id(board_id, &boards.iter().map(|b| b.id.as_str()).collect::<Vec<_>>())
        .map_err(|e| anyhow!("{}", e))?;

    // Check for duplicate name (excluding this board)
    if boards.iter().any(|b| b.id != resolved_id && b.name == new_name) {
        return Err(DomainError::DuplicateBoardName { name: new_name.to_string() }.into());
    }

    let conn = db.conn_mut();
    let sql = "UPDATE board SET name = ?1, updated_at = ?2 WHERE id = ?3";
    conn.execute(
        sql,
        rusqlite::params![new_name, now(), resolved_id],
    ).context("failed to rename board")?;

    Ok(())
}

// ── Column operations ─────────────────────────────────────────────────────

/// Add a column to a board.
pub fn add_column(db: &Db, board_id: &str, name: &str) -> Result<Column> {
    validate_column_name(name, &[]).map_err(|e| anyhow!("{}", e))?;

    let state = db.load_board_state(board_id)
        .map_err(|_| DomainError::BoardNotFound { id: board_id.to_string() })?;

    validate_column_name(name, &state.columns).map_err(|e| anyhow!("{}", e))?;

    let positions: Vec<i32> = state.columns.iter().map(|c| c.position).collect();
    let next_pos = next_position(&positions);

    let column = Column {
        id: gen_id(),
        board_id: board_id.to_string(),
        name: name.to_string(),
        position: next_pos,
        created_at: now(),
        updated_at: now(),
    };

    let conn = db.conn_mut();
    let (sql, params) = insert_column_sql(&column);
    exec_with_params(&conn, &sql, &params)?;

    Ok(column)
}

/// Rename a column.
pub fn rename_column(db: &Db, column_id_prefix: &str, new_name: &str) -> Result<()> {
    validate_column_name(new_name, &[]).map_err(|e| anyhow!("{}", e))?;

    let state = load_board_state_for_columns(db)?;
    let resolved_id = resolve_column_id(&state, column_id_prefix)?;
    validate_column_name(new_name, &state.columns).map_err(|e| anyhow!("{}", e))?;

    let conn = db.conn_mut();
    let sql = "UPDATE column_ SET name = ?1, updated_at = ?2 WHERE id = ?3";
    conn.execute(
        sql,
        rusqlite::params![new_name, now(), resolved_id],
    ).context("failed to rename column")?;

    Ok(())
}

/// Remove a column with the specified orphan action.
pub fn remove_column(db: &Db, column_id_prefix: &str, orphan_action: OrphanAction) -> Result<()> {
    let state = load_board_state_for_columns(db)?;
    let resolved_id = resolve_column_id(&state, column_id_prefix)?;

    // Cannot delete the last column
    if state.columns.len() <= 1 {
        return Err(DomainError::CannotDeleteLastColumn.into());
    }

    // Find the column's board_id
    let board_id = state.columns.iter()
        .find(|c| c.id == resolved_id)
        .map(|c| c.board_id.clone())
        .ok_or_else(|| DomainError::ColumnNotFound { id: resolved_id.clone() })?;

    let mut conn = db.conn_mut();

    // Count tasks in this column
    let task_count: i64 = conn.query_row(
        "SELECT COUNT(*) FROM task WHERE column_id = ?1",
        rusqlite::params![&resolved_id],
        |row| row.get(0),
    ).context("failed to count tasks")?;

    let tx = conn.transaction().context("failed to begin transaction")?;

    if task_count > 0 {
        match orphan_action {
            OrphanAction::MoveToFirst => {
                // Find the column that will have position 0 after deletion
                let remaining: Vec<&Column> = state.columns.iter()
                    .filter(|c| c.id != resolved_id)
                    .collect();
                let sorted = recompute_positions(
                    &remaining.iter().map(|c| (c.id.clone(), c.position)).collect::<Vec<_>>()
                );
                // The first column after recomputation gets position 0
                let target_column_id = &sorted[0].0;

                // Move all tasks to the target column
                let (sql, params) = move_tasks_to_column_sql(&resolved_id, target_column_id);
                exec_with_params_raw(&tx, &sql, &params)?;

                // Fetch all tasks in target column and recompute positions
                let new_positions = {
                    let mut stmt = tx.prepare(
                        "SELECT id, position FROM task WHERE column_id = ?1 ORDER BY position"
                    ).context("failed to prepare task query")?;
                    let task_rows = stmt.query_map(rusqlite::params![target_column_id], |row| {
                        Ok((row.get::<_, String>(0)?, row.get::<_, i32>(1)?))
                    }).context("failed to query tasks")?;
                    let task_rows: Vec<(String, i32)> = task_rows
                        .collect::<std::result::Result<Vec<_>, _>>()
                        .context("failed to collect tasks")?;
                    recompute_positions(&task_rows)
                };
                for (id, pos) in &new_positions {
                    let (sql, params) = update_position_sql(EntityTable::Task, id, *pos);
                    exec_with_params_raw(&tx, &sql, &params)?;
                }
            }
            OrphanAction::Delete => {
                let (sql, params) = delete_tasks_by_column_sql(&resolved_id);
                exec_with_params_raw(&tx, &sql, &params)?;
            }
        }
    }

    // Delete the column
    let (sql, params) = delete_column_sql(&resolved_id);
    exec_with_params_raw(&tx, &sql, &params)?;

    // Recompute remaining column positions
    let new_positions = {
        let mut stmt = tx.prepare(
            "SELECT id, position FROM column_ WHERE board_id = ?1 ORDER BY position"
        ).context("failed to prepare column query")?;
        let remaining_columns = stmt.query_map(rusqlite::params![&board_id], |row| {
            Ok((row.get::<_, String>(0)?, row.get::<_, i32>(1)?))
        }).context("failed to query columns")?
        .collect::<std::result::Result<Vec<_>, _>>()
        .context("failed to collect columns")?;
        recompute_positions(&remaining_columns)
    };
    for (id, pos) in &new_positions {
        let (sql, params) = update_position_sql(EntityTable::Column, id, *pos);
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    tx.commit().context("failed to commit transaction")?;

    Ok(())
}

/// Move a column to a new position.
pub fn move_column(db: &Db, column_id_prefix: &str, new_position: i32) -> Result<()> {
    let state = load_board_state_for_columns(db)?;
    let resolved_id = resolve_column_id(&state, column_id_prefix)?;

    let max_pos = if state.columns.is_empty() { 0 } else { state.columns.len() as i32 };
    if new_position < 0 || new_position >= max_pos {
        return Err(DomainError::PositionOutOfRange {
            position: new_position,
            max: max_pos,
        }.into());
    }

    let column = state.columns.iter().find(|c| c.id == resolved_id).ok_or_else(|| {
        DomainError::ColumnNotFound { id: resolved_id.clone() }
    })?;

    let old_position = column.position;

    let mut conn = db.conn_mut();
    let tx = conn.transaction().context("failed to begin transaction")?;

    // Compute new positions for all columns
    let items: Vec<(String, i32)> = state.columns
        .iter()
        .map(|c| (c.id.clone(), c.position))
        .collect();

    let shifted = positions_after_move(&items, old_position, new_position);
    let new_positions = recompute_positions(&shifted);

    for (id, pos) in &new_positions {
        let (sql, params) = update_position_sql(EntityTable::Column, id, *pos);
        exec_with_params_raw(&tx, &sql, &params)?;
    }

    tx.commit().context("failed to commit transaction")?;

    Ok(())
}

/// List columns for a board.
pub fn list_columns(db: &Db, board_id: &str) -> Result<Vec<Column>> {
    let state = db.load_board_state(board_id)
        .map_err(|_| DomainError::BoardNotFound { id: board_id.to_string() })?;
    Ok(state.columns)
}

// ── Task operations ───────────────────────────────────────────────────────

/// Add a task to a column.
pub fn add_task(db: &Db, column_id_prefix: &str, title: &str, desc: &str, priority_id_prefix: &str) -> Result<Task> {
    validate_title(title).map_err(|e| anyhow!("{}", e))?;

    let state = load_board_state_for_tasks(db)?;
    let resolved_column_id = resolve_column_id(&state, column_id_prefix)?;
    validate_column_exists(&resolved_column_id, &state.columns).map_err(|e| anyhow!("{}", e))?;

    // Resolve priority
    let resolved_priority_id = resolve_id(
        priority_id_prefix,
        &state.priorities.iter().map(|p| p.id.as_str()).collect::<Vec<_>>(),
    ).map_err(|e| anyhow!("{}", e))?;

    validate_priority(&resolved_priority_id, &state.priorities).map_err(|e| anyhow!("{}", e))?;

    // Find tasks in the target column to compute next position
    let column_tasks: Vec<&Task> = state.tasks.iter()
        .filter(|t| t.column_id == resolved_column_id)
        .collect();
    let positions: Vec<i32> = column_tasks.iter().map(|t| t.position).collect();
    let next_pos = next_position(&positions);

    let task = Task {
        id: gen_id(),
        column_id: resolved_column_id,
        title: title.to_string(),
        description: desc.to_string(),
        priority_id: resolved_priority_id,
        position: next_pos,
        created_at: now(),
        updated_at: now(),
    };

    let conn = db.conn_mut();
    let (sql, params) = insert_task_sql(&task);
    exec_with_params(&conn, &sql, &params)?;

    Ok(task)
}

/// Edit a task.
pub fn edit_task(db: &Db, task_id_prefix: &str, changes: &TaskChanges) -> Result<()> {
    let state = load_board_state_for_tasks(db)?;
    let resolved_id = resolve_task_id(&state, task_id_prefix)?;

    // Validate priority if changed
    if let Some(ref priority_id) = changes.priority_id {
        validate_priority(priority_id, &state.priorities)
            .map_err(|e| anyhow!("{}", e))?;
    }

    // Validate column if changed
    if let Some(ref column_id) = changes.column_id {
        validate_column_exists(column_id, &state.columns)
            .map_err(|e| anyhow!("{}", e))?;
    }

    // Validate title if changed
    if let Some(ref title) = changes.title {
        validate_title(title)
            .map_err(|e| anyhow!("{}", e))?;
    }

    let conn = db.conn_mut();
    let (sql, params) = update_task_sql(&resolved_id, changes);
    exec_with_params(&conn, &sql, &params)?;

    Ok(())
}

/// Move a task to a different column/position.
pub fn move_task(db: &Db, task_id_prefix: &str, target_column_prefix: &str, position: Option<i32>) -> Result<()> {
    let state = load_board_state_for_tasks(db)?;
    let resolved_task_id = resolve_task_id(&state, task_id_prefix)?;
    let resolved_column_id = resolve_column_id(&state, target_column_prefix)?;

    let _task = state.tasks.iter().find(|t| t.id == resolved_task_id).ok_or_else(|| {
        DomainError::TaskNotFound { id: resolved_task_id.clone() }
    })?;

    let mut conn = db.conn_mut();
    let tx = conn.transaction().context("failed to begin transaction")?;

    let target_position = if let Some(pos) = position {
        pos
    } else {
        // Append at end of target column
        let target_tasks: Vec<i32> = state.tasks.iter()
            .filter(|t| t.column_id == resolved_column_id && t.id != resolved_task_id)
            .map(|t| t.position)
            .collect();
        next_position(&target_tasks)
    };

    let sql = "UPDATE task SET column_id = ?1, position = ?2, updated_at = ?3 WHERE id = ?4";
    tx.execute(
        sql,
        rusqlite::params![resolved_column_id, target_position, now(), resolved_task_id],
    ).context("failed to move task")?;

    tx.commit().context("failed to commit transaction")?;

    Ok(())
}

/// Remove a task.
pub fn remove_task(db: &Db, task_id_prefix: &str) -> Result<()> {
    let state = load_board_state_for_tasks(db)?;
    let resolved_id = resolve_task_id(&state, task_id_prefix)?;

    let conn = db.conn_mut();
    let (sql, params) = delete_task_sql(&resolved_id);
    exec_with_params(&conn, &sql, &params)?;

    Ok(())
}

/// Show a single task.
pub fn show_task(db: &Db, task_id_prefix: &str) -> Result<Task> {
    let state = load_board_state_for_tasks(db)?;
    let resolved_id = resolve_task_id(&state, task_id_prefix)?;

    state.tasks.iter()
        .find(|t| t.id == resolved_id)
        .cloned()
        .ok_or_else(|| anyhow!("task not found: '{}'", resolved_id))
}

/// List tasks with optional filtering.
pub fn list_tasks(db: &Db, board_id: &str, filter: &TaskFilter) -> Result<Vec<Task>> {
    let state = db.load_board_state(board_id)
        .map_err(|_| DomainError::BoardNotFound { id: board_id.to_string() })?;

    let mut tasks = state.tasks;

    // Apply column filter
    if let Some(ref col_id) = filter.column_id {
        let resolved_col_id = resolve_id(
            col_id,
            &state.columns.iter().map(|c| c.id.as_str()).collect::<Vec<_>>(),
        ).map_err(|e| anyhow!("{}", e))?;
        tasks.retain(|t| t.column_id == resolved_col_id);
    }

    // Apply priority filter
    if let Some(ref prio_id) = filter.priority_id {
        let resolved_prio_id = resolve_id(
            prio_id,
            &state.priorities.iter().map(|p| p.id.as_str()).collect::<Vec<_>>(),
        ).map_err(|e| anyhow!("{}", e))?;
        tasks.retain(|t| t.priority_id == resolved_prio_id);
    }

    Ok(tasks)
}

// ── Internal helpers ──────────────────────────────────────────────────────

fn resolve_column_id(state: &crate::core::BoardState, prefix: &str) -> Result<String> {
    let ids: Vec<&str> = state.columns.iter().map(|c| c.id.as_str()).collect();

    // Try ID resolution first
    if let Ok(id) = resolve_id(prefix, &ids) {
        return Ok(id);
    }

    // Fall back to case-insensitive name matching
    let matches: Vec<&Column> = state.columns.iter()
        .filter(|c| c.name.eq_ignore_ascii_case(prefix))
        .collect();

    match matches.len() {
        0 => Err(DomainError::ColumnNotFound { id: prefix.to_string() }.into()),
        1 => Ok(matches[0].id.clone()),
        _ => Err(anyhow!("multiple columns match name '{}'", prefix)),
    }
}

fn resolve_task_id(state: &crate::core::BoardState, prefix: &str) -> Result<String> {
    let ids: Vec<&str> = state.tasks.iter().map(|t| t.id.as_str()).collect();
    resolve_id(prefix, &ids).map_err(|e| anyhow!("{}", e))
}

/// Load board state for operations that need columns (auto-detects board).
fn load_board_state_for_columns(db: &Db) -> Result<crate::core::BoardState> {
    let boards = db.list_boards()?;
    let board = boards.first().ok_or_else(|| {
        anyhow::anyhow!("no boards found; run 'init' first")
    })?;

    db.load_board_state(&board.id)
}

/// Load board state for task operations (same as columns, loads all data).
fn load_board_state_for_tasks(db: &Db) -> Result<crate::core::BoardState> {
    load_board_state_for_columns(db)
}

CREATE TABLE board (
    id         TEXT PRIMARY KEY,
    name       TEXT NOT NULL,
    created_at TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE priority (
    id   TEXT PRIMARY KEY,
    name TEXT NOT NULL UNIQUE
);

CREATE TABLE column_ (
    id         TEXT PRIMARY KEY,
    board_id   TEXT NOT NULL REFERENCES board(id) ON DELETE CASCADE,
    name       TEXT NOT NULL,
    position   INTEGER NOT NULL,
    created_at TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE task (
    id          TEXT PRIMARY KEY,
    column_id   TEXT NOT NULL REFERENCES column_(id),
    title       TEXT NOT NULL,
    description TEXT NOT NULL DEFAULT '',
    priority_id TEXT NOT NULL REFERENCES priority(id),
    position    INTEGER NOT NULL,
    created_at  TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at  TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE _migrations (
    id         INTEGER PRIMARY KEY,
    name       TEXT NOT NULL,
    applied_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE INDEX idx_column_board ON column_(board_id, position);
CREATE INDEX idx_task_column ON task(column_id, position);

